    assert!(ABOUT_SLINT.contains(&slint_assignment("text", ABOUT_TITLE_LABEL)));
    assert!(ABOUT_SLINT.contains(&slint_assignment("text", ABOUT_CREDIT_LABEL)));
    for resource_path in IMAGE_RESOURCE_PATHS {
